101	  public synchronized int sniEntrySize() {
102	    int size = 0;
103	    for (Future<SslContextProvider> fut : sslContextProviderMap.values()) {
104	      SslContextProvider result = fut.result();
105	      if (result != null) {
106	        size += result.sniEntrySize();
107	      }
108	    }
109	    return size;
110	  }
