239	  private static class LruCache<K, V> extends LinkedHashMap<K, V> {
240	
241	    private final int maxSize;
242	
243	    public LruCache(int maxSize) {
244	      if (maxSize < 1) {
245	        throw new UnsupportedOperationException();
246	      }
247	      this.maxSize = maxSize;
248	    }
249	
250	    @Override
251	    protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
252	      return size() > maxSize;
253	    }
254	  }
