256	  private final static class ConfigKey {
257	    private final KeyCertOptions keyCertOptions;
258	    private final TrustOptions trustOptions;
259	    private final List<Buffer> crlValues;
260	    public ConfigKey(SSLOptions options) {
261	      this(options.getKeyCertOptions(), trustOptionsOf(options), options.getCrlValues());
262	    }
263	    public ConfigKey(KeyCertOptions keyCertOptions, TrustOptions trustOptions, List<Buffer> crlValues) {
264	      this.keyCertOptions = keyCertOptions;
265	      this.trustOptions = trustOptions;
266	      this.crlValues = crlValues != null ? new ArrayList<>(crlValues) : null;
267	    }
268	
269	    @Override
270	    public boolean equals(Object obj) {
271	      if (obj == this) {
272	        return true;
273	      }
274	      if (obj instanceof ConfigKey) {
275	        ConfigKey that = (ConfigKey) obj;
276	        return Objects.equals(keyCertOptions, that.keyCertOptions) && Objects.equals(trustOptions, that.trustOptions) && Objects.equals(crlValues, that.crlValues);
277	      }
278	      return false;
279	    }
280	
281	    @Override
282	    public int hashCode() {
283	      int hashCode = Objects.hashCode(keyCertOptions);
284	      hashCode = 31 * hashCode + Objects.hashCode(trustOptions);
285	      hashCode = 31 * hashCode + Objects.hashCode(crlValues);
286	      return hashCode;
287	    }
288	  }
