276	  private VertxTrustManagerFactory buildVertxTrustManagerFactory(TrustManager[] mgrs) {
277	    if (crls != null && crls.size() > 0) {
278	      mgrs = createUntrustRevokedCertTrustManager(mgrs, crls);
279	    }
280	    return new VertxTrustManagerFactory(mgrs);
281	  }
