283	  /*
284	  Proxy the specified trust managers with an implementation checking first the provided certificates
285	  against the Certificate Revocation List (crl) before delegating to the original trust managers.
286	   */
287	  private static TrustManager[] createUntrustRevokedCertTrustManager(TrustManager[] trustMgrs, List<CRL> crls) {
288	    trustMgrs = trustMgrs.clone();
289	    for (int i = 0;i < trustMgrs.length;i++) {
290	      TrustManager trustMgr = trustMgrs[i];
291	      if (trustMgr instanceof X509TrustManager) {
292	        X509TrustManager x509TrustManager = (X509TrustManager) trustMgr;
293	        trustMgrs[i] = new X509TrustManager() {
294	          @Override
295	          public void checkClientTrusted(X509Certificate[] x509Certificates, String s) throws CertificateException {
296	            checkRevoked(x509Certificates);
297	            x509TrustManager.checkClientTrusted(x509Certificates, s);
298	          }
299	          @Override
300	          public void checkServerTrusted(X509Certificate[] x509Certificates, String s) throws CertificateException {
301	            checkRevoked(x509Certificates);
302	            x509TrustManager.checkServerTrusted(x509Certificates, s);
303	          }
304	          private void checkRevoked(X509Certificate[] x509Certificates) throws CertificateException {
305	            for (X509Certificate cert : x509Certificates) {
306	              for (CRL crl : crls) {
307	                if (crl.isRevoked(cert)) {
308	                  throw new CertificateException("Certificate revoked");
309	                }
310	              }
311	            }
312	          }
313	          @Override
314	          public X509Certificate[] getAcceptedIssuers() {
315	            return x509TrustManager.getAcceptedIssuers();
316	          }
317	        };
318	      }
319	    }
320	    return trustMgrs;
321	  }
