323	  public void configureEngine(SSLEngine engine, Set<String> enabledProtocols, String serverName, boolean client) {
324	    Set<String> protocols = new LinkedHashSet<>(enabledProtocols);
325	    protocols.retainAll(Arrays.asList(engine.getSupportedProtocols()));
326	    engine.setEnabledProtocols(protocols.toArray(new String[protocols.size()]));
327	    if (client) {
328	      SSLParameters sslParameters = engine.getSSLParameters();
329	      sslParameters.setEndpointIdentificationAlgorithm(endpointIdentificationAlgorithm != null ? endpointIdentificationAlgorithm : "");
330	      engine.setSSLParameters(sslParameters);
331	    }
332	    if (serverName != null) {
333	      SSLParameters sslParameters = engine.getSSLParameters();
334	      sslParameters.setServerNames(Collections.singletonList(new SNIHostName(serverName)));
335	      engine.setSSLParameters(sslParameters);
336	    }
337	  }
